head.b:skin:
/* ============================================
   Mi Biblia 365 - Sistema de Diseño | Z.IA
   ============================================ */

:root {
  /* Colores modo claro */
  --bg-primary: #faf9f7;
  --bg-secondary: #ffffff;
  --bg-tertiary: #f5f3ef;
  --bg-card: #ffffff;
  --bg-elevated: #ffffff;

  --text-primary: #1a1a1a;
  --text-secondary: #4a4a4a;
  --text-tertiary: #6b6b6b;
  --text-muted: #8b8b8b;

  --accent-primary: #1a365d;
  --accent-secondary: #2c5282;
  --accent-tertiary: #3182ce;
  --accent-gold: #b7791f;
  --accent-gold-light: #d69e2e;

  --border-light: #e8e6e3;
  --border-medium: #d4d2cf;

  --shadow-sm: 0 1px 2px rgba(26, 54, 93, 0.04);
  --shadow-md: 0 4px 12px rgba(26, 54, 93, 0.08);
  --shadow-lg: 0 8px 24px rgba(26, 54, 93, 0.12);

  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-serif: 'Playfair Display', Georgia, serif;

  --transition-fast: 150ms ease;
  --transition-base: 250ms ease;
  --transition-slow: 400ms ease;

  --spacing-xs: 4px;
  --spacing-sm: 8px;
  --spacing-md: 16px;
  --spacing-lg: 24px;
  --spacing-xl: 32px;
  --spacing-2xl: 48px;
  --spacing-3xl: 64px;

  --nav-height: 64px;
  --nav-mobile-height: 56px;
  --bottom-nav-height: 72px;

  --safe-area-inset-bottom: env(safe-area-inset-bottom, 0px);
}

/* Modo oscuro */
[data-theme="dark"] {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #1c2128;
  --bg-card: #161b22;
  --bg-elevated: #21262d;

  --text-primary: #f0f6fc;
  --text-secondary: #c9d1d9;
  --text-tertiary: #8b949e;
  --text-muted: #6e7681;

  --accent-primary: #58a6ff;
  --accent-secondary: #79c0ff;
  --accent-tertiary: #a5d6ff;
  --accent-gold: #d29922;
  --accent-gold-light: #e3b341;

  --border-light: #30363d;
  --border-medium: #484f58;

  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.2);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.4);
}

/* Reset y base */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: var(--font-sans);
  background-color: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  min-height: 100vh;
  overflow-x: hidden;
  transition: background-color var(--transition-base), color var(--transition-base);
}

/* Ocultar elementos de Blogger */
.widget { display: none !important; }
#blog1 { display: none !important; }
.blog-feeds { display: none !important; }
.post-feeds { display: none !important; }
.feed-links { display: none !important; }
.blog-pager { display: none !important; }

/* ============================================
   Layout Principal
   ============================================ */

.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* Header */
.app-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: var(--nav-height);
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-light);
  z-index: 100;
  display: flex;
  align-items: center;
  padding: 0 var(--spacing-lg);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.header-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
}

.logo {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  text-decoration: none;
  color: var(--text-primary);
}

.logo-icon {
  width: 36px;
  height: 36px;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
}

.logo-icon svg {
  width: 20px;
  height: 20px;
  color: white;
}

.logo-text {
  font-family: var(--font-serif);
  font-size: 1.25rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.logo-text span {
  color: var(--accent-gold);
}

/* Navegación desktop */
.nav-desktop {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.nav-link {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  color: var(--text-secondary);
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 500;
  border-radius: var(--radius-md);
  transition: all var(--transition-fast);
}

.nav-link:hover {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.nav-link.active {
  background: var(--bg-tertiary);
  color: var(--accent-primary);
}

.nav-link svg {
  width: 18px;
  height: 18px;
}

/* Acciones del header */
.header-actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.btn-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  border: none;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition-fast);
}

.btn-icon:hover {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.btn-icon svg {
  width: 20px;
  height: 20px;
}

/* Contenido principal */
.main-content {
  flex: 1;
  padding-top: var(--nav-height);
  padding-bottom: calc(var(--bottom-nav-height) + var(--safe-area-inset-bottom));
}

/* Navegación móvil inferior */
.nav-mobile {
  display: none;
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: calc(var(--bottom-nav-height) + var(--safe-area-inset-bottom));
  padding-bottom: var(--safe-area-inset-bottom);
  background: var(--bg-secondary);
  border-top: 1px solid var(--border-light);
  z-index: 100;
}

.nav-mobile-inner {
  display: flex;
  align-items: center;
  justify-content: space-around;
  height: var(--bottom-nav-height);
  padding: 0 var(--spacing-sm);
}

.nav-mobile-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2px;
  padding: var(--spacing-sm) var(--spacing-md);
  color: var(--text-tertiary);
  text-decoration: none;
  font-size: 0.7rem;
  font-weight: 500;
  border-radius: var(--radius-md);
  transition: all var(--transition-fast);
  min-width: 64px;
}

.nav-mobile-item svg {
  width: 24px;
  height: 24px;
}

.nav-mobile-item.active {
  color: var(--accent-primary);
}

.nav-mobile-item.leer-hoy {
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  color: white;
  padding: var(--spacing-md);
  border-radius: 50%;
  min-width: 56px;
  height: 56px;
  margin-top: -20px;
  box-shadow: var(--shadow-lg);
}

.nav-mobile-item.leer-hoy svg {
  width: 26px;
  height: 26px;
}

/* ============================================
   Contenedores de páginas
   ============================================ */

.page-container {
  max-width: 800px;
  margin: 0 auto;
  padding: var(--spacing-lg);
}

.page-container.wide {
  max-width: 1200px;
}

/* Página de inicio */
.home-hero {
  text-align: center;
  padding: var(--spacing-2xl) var(--spacing-lg);
}

.home-greeting {
  font-size: 0.95rem;
  color: var(--text-tertiary);
  margin-bottom: var(--spacing-sm);
}

.home-title {
  font-family: var(--font-serif);
  font-size: 2rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-md);
  line-height: 1.2;
}

.home-subtitle {
  font-size: 1rem;
  color: var(--text-secondary);
  max-width: 400px;
  margin: 0 auto var(--spacing-xl);
}

/* Botones */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-xl);
  font-family: var(--font-sans);
  font-size: 0.95rem;
  font-weight: 600;
  border-radius: var(--radius-md);
  border: none;
  cursor: pointer;
  text-decoration: none;
  transition: all var(--transition-fast);
}

.btn-primary {
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  color: white;
  box-shadow: var(--shadow-md);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-lg);
}

.btn-secondary {
  background: var(--bg-tertiary);
  color: var(--text-primary);
  border: 1px solid var(--border-light);
}

.btn-secondary:hover {
  background: var(--bg-elevated);
  border-color: var(--border-medium);
}

.btn-lg {
  padding: var(--spacing-lg) var(--spacing-2xl);
  font-size: 1.05rem;
  border-radius: var(--radius-lg);
}

.btn svg {
  width: 18px;
  height: 18px;
}

/* Cards */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  padding: var(--spacing-lg);
  box-shadow: var(--shadow-sm);
  transition: all var(--transition-base);
}

.card:hover {
  box-shadow: var(--shadow-md);
}

/* Versículo del día */
.verse-card {
  background: linear-gradient(135deg, var(--bg-card), var(--bg-tertiary));
  border: 1px solid var(--border-light);
  border-radius: var(--radius-xl);
  padding: var(--spacing-xl);
  margin: var(--spacing-xl) 0;
  position: relative;
  overflow: hidden;
}

.verse-card::before {
  content: '"';
  position: absolute;
  top: -20px;
  left: 20px;
  font-family: var(--font-serif);
  font-size: 120px;
  color: var(--accent-primary);
  opacity: 0.08;
  line-height: 1;
}

.verse-label {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--accent-gold);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: var(--spacing-md);
}

.verse-text {
  font-family: var(--font-serif);
  font-size: 1.25rem;
  line-height: 1.7;
  color: var(--text-primary);
  margin-bottom: var(--spacing-md);
  font-style: italic;
}

.verse-reference {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--accent-primary);
}

/* Progreso */
.progress-section {
  margin: var(--spacing-xl) 0;
}

.progress-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--spacing-md);
}

.progress-title {
  font-weight: 600;
  color: var(--text-primary);
}

.progress-percent {
  font-size: 0.85rem;
  color: var(--accent-primary);
  font-weight: 600;
}

.progress-bar {
  height: 8px;
  background: var(--bg-tertiary);
  border-radius: 100px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--accent-primary), var(--accent-gold));
  border-radius: 100px;
  transition: width var(--transition-slow);
}

/* Quick actions */
.quick-actions {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);
  margin: var(--spacing-xl) 0;
}

.quick-action {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-lg);
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  text-decoration: none;
  color: var(--text-primary);
  transition: all var(--transition-fast);
}

.quick-action:hover {
  border-color: var(--accent-primary);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.quick-action-icon {
  width: 48px;
  height: 48px;
  background: var(--bg-tertiary);
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent-primary);
}

.quick-action-icon svg {
  width: 24px;
  height: 24px;
}

.quick-action-label {
  font-size: 0.9rem;
  font-weight: 500;
}

/* Planes grid */
.plans-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: var(--spacing-lg);
  margin: var(--spacing-xl) 0;
}

.plan-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  padding: var(--spacing-lg);
  transition: all var(--transition-base);
}

.plan-card:hover {
  border-color: var(--accent-primary);
  box-shadow: var(--shadow-md);
}

.plan-card-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: var(--spacing-md);
}

.plan-icon {
  width: 44px;
  height: 44px;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
}

.plan-icon svg {
  width: 22px;
  height: 22px;
}

.plan-badge {
  font-size: 0.7rem;
  font-weight: 600;
  padding: 4px 10px;
  background: var(--bg-tertiary);
  color: var(--text-tertiary);
  border-radius: 100px;
}

.plan-name {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: var(--spacing-xs);
}

.plan-description {
  font-size: 0.85rem;
  color: var(--text-tertiary);
  margin-bottom: var(--spacing-md);
  line-height: 1.5;
}

.plan-meta {
  display: flex;
  gap: var(--spacing-md);
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.plan-meta-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.plan-meta-item svg {
  width: 14px;
  height: 14px;
}

/* ============================================
   Loading y estados
   ============================================ */

.skeleton {
  background: linear-gradient(90deg, var(--bg-tertiary) 25%, var(--bg-elevated) 50%, var(--bg-tertiary) 75%);
  background-size: 200% 100%;
  animation: skeleton-loading 1.5s infinite;
  border-radius: var(--radius-sm);
}

@keyframes skeleton-loading {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.loading-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-3xl);
  gap: var(--spacing-md);
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid var(--border-light);
  border-top-color: var(--accent-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================================
   Responsive
   ============================================ */

@media (max-width: 768px) {
  :root {
    --nav-height: var(--nav-mobile-height);
  }

  .nav-desktop {
    display: none;
  }

  .nav-mobile {
    display: block;
  }

  .page-container {
    padding: var(--spacing-md);
  }

  .home-hero {
    padding: var(--spacing-lg) var(--spacing-md);
  }

  .home-title {
    font-size: 1.5rem;
  }

  .quick-actions {
    grid-template-columns: 1fr;
  }

  .verse-card {
    padding: var(--spacing-lg);
  }

  .verse-text {
    font-size: 1.1rem;
  }
}

@media (min-width: 769px) {
  .nav-mobile {
    display: none !important;
  }
}

/* ============================================
   Utilidades
   ============================================ */

.hidden { display: none !important; }
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.text-center { text-align: center; }
.text-muted { color: var(--text-tertiary); }

.mt-md { margin-top: var(--spacing-md); }
.mt-lg { margin-top: var(--spacing-lg); }
.mb-md { margin-bottom: var(--spacing-md); }
.mb-lg { margin-bottom: var(--spacing-lg); }

/* Focus states para accesibilidad */
:focus-visible {
  outline: 2px solid var(--accent-primary);
  outline-offset: 2px;
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

body.script:
//
(function() {
  'use strict';

  // ==========================================
  // Configuración
  // ==========================================
  const CONFIG = {
    CDN_BASE: 'https://cdn.jsdelivr.net/gh/tu-usuario/mibiblia365@main',
    API_BASE: 'https://docs-bible-api.netlify.app/api',
    API_BACKUP: 'https://api.scripture.api.bible/v1',
    API_KEY: 'lKDNAnTqVMi4Mc32rwonP',
    DEFAULT_VERSION: 'rv1960',
    STORAGE_KEY: 'mibiblia365_data'
  };

  // ==========================================
  // Estado global
  // ==========================================
  const state = {
    theme: localStorage.getItem('theme') || 'light',
    currentPage: 'home',
    user: null,
    plan: null,
    version: CONFIG.DEFAULT_VERSION
  };

  // ==========================================
  // Utilidades
  // ==========================================
  function $(selector) {
    return document.querySelector(selector);
  }

  function $$(selector) {
    return document.querySelectorAll(selector);
  }

  function show(el) {
    if (el) el.classList.remove('hidden');
  }

  function hide(el) {
    if (el) el.classList.add('hidden');
  }

  // ==========================================
  // Sistema de temas
  // ==========================================
  function initTheme() {
    const savedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    state.theme = savedTheme || (prefersDark ? 'dark' : 'light');
    applyTheme();

    const toggleBtn = $('#theme-toggle');
    if (toggleBtn) {
      toggleBtn.addEventListener('click', toggleTheme);
    }
  }

  function applyTheme() {
    document.documentElement.setAttribute('data-theme', state.theme);

    const sunIcon = $('.icon-sun');
    const moonIcon = $('.icon-moon');

    if (state.theme === 'dark') {
      hide(sunIcon);
      show(moonIcon);
    } else {
      show(sunIcon);
      hide(moonIcon);
    }
  }

  function toggleTheme() {
    state.theme = state.theme === 'light' ? 'dark' : 'light';
    localStorage.setItem('theme', state.theme);
    applyTheme();
  }

  // ==========================================
  // Navegación y detección de página
  // ==========================================
  function detectCurrentPage() {
    const path = window.location.pathname;

    if (path === '/' || path === '') {
      return 'home';
    }

    const pageMap = {
      '/p/leer-hoy.html': 'leer-hoy',
      '/p/planes.html': 'planes',
      '/p/plan-completo.html': 'plan-completo',
      '/p/biblia.html': 'biblia',
      '/p/buscar.html': 'buscar',
      '/p/mi-espacio.html': 'mi-espacio',
      '/p/acerca.html': 'acerca',
      '/p/preguntas-frecuentes.html': 'faq',
      '/p/instalar.html': 'instalar'
    };

    return pageMap[path] || 'home';
  }

  function updateActiveNav() {
    const page = state.currentPage;

    // Desktop nav
    $$('.nav-link').forEach(link => {
      const linkPage = link.getAttribute('data-page');
      if (linkPage === page) {
        link.classList.add('active');
      } else {
        link.classList.remove('active');
      }
    });

    // Mobile nav
    $$('.nav-mobile-item').forEach(item => {
      const itemPage = item.getAttribute('data-page');
      if (itemPage === page) {
        item.classList.add('active');
      } else {
        item.classList.remove('active');
      }
    });
  }

  // ==========================================
  // Gestión de datos del usuario
  // ==========================================
  function getUserData() {
    try {
      const data = localStorage.getItem(CONFIG.STORAGE_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error('Error reading user data:', e);
      return null;
    }
  }

  function saveUserData(data) {
    try {
      localStorage.setItem(CONFIG.STORAGE_KEY, JSON.stringify(data));
    } catch (e) {
      console.error('Error saving user data:', e);
    }
  }

  function initUserData() {
    const data = getUserData();

    if (!data) {
      // Crear estructura inicial
      const initialData = {
        version: '1.0',
        lastSync: new Date().toISOString().split('T')[0],
        config: {
          preferredVersion: CONFIG.DEFAULT_VERSION,
          darkMode: state.theme === 'dark',
          fontSize: 'medium',
          activePlanId: null,
          leapYearMode: 'gracia'
        },
        plans: [],
        favorites: [],
        notes: [],
        history: {
          readings: [],
          searches: [],
          chapters: []
        }
      };

      saveUserData(initialData);
      state.user = initialData;
    } else {
      state.user = data;
      state.version = data.config.preferredVersion || CONFIG.DEFAULT_VERSION;
    }
  }

  // ==========================================
  // Actualización de UI
  // ==========================================
  function updateHomeProgress() {
    const userData = state.user;
    const progressSection = $('#progress-section');

    if (!userData || !userData.config.activePlanId) {
      hide(progressSection);
      return;
    }

    const activePlan = userData.plans.find(p => p.planId === userData.config.activePlanId);

    if (!activePlan) {
      hide(progressSection);
      return;
    }

    show(progressSection);

    const planName = $('#plan-name');
    const progressPercent = $('#progress-percent');
    const progressFill = $('#progress-fill');
    const progressStatus = $('#progress-status');

    if (planName) planName.textContent = 'Biblia en un año';

    const completed = activePlan.completedDays.length;
    const percent = Math.round((completed / 365) * 100);

    if (progressPercent) progressPercent.textContent = percent + '%';
    if (progressFill) progressFill.style.width = percent + '%';
    if (progressStatus) progressStatus.textContent = 'Día ' + activePlan.lastOpenedDay + ' de 365';
  }

  // ==========================================
  // Inicialización
  // ==========================================
  function init() {
    initTheme();
    initUserData();

    state.currentPage = detectCurrentPage();
    updateActiveNav();

    // Actualizar UI según página actual
    if (state.currentPage === 'home') {
      updateHomeProgress();
    }

    // Escuchar cambios de tema del sistema
    window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
      if (!localStorage.getItem('theme')) {
        state.theme = e.matches ? 'dark' : 'light';
        applyTheme();
      }
    });

    console.log('Mi Biblia 365 initialized');
  }

  // Ejecutar cuando el DOM esté listo
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();
//
